<template>
    <view>
        <view class="container">
            <view class="memCount">
                <view class="mem1">
                    メンバー数
                </view>
                <view class="mem2">
                    <text>280</text>/300
                </view>
            </view>
            <view class="title">
                メンバーリストを選択してください
            </view>
            <view class="chooseItem">
                <view class="item">
                    <view class="itemLeft">
                        <view class="unselect" @click="changeTab(0)" v-if="current == 1"></view>
                        <view class="selected" v-if="current == 0">
                            <view class="fill"></view>
                        </view>
                    </view>
                    <view class="itemRight" :style="current == 0? 'color:#1D1D1F;' : 'color: #AAAAAA' ">
                        すべて
                    </view>
                </view>
                <view class="item">
                    <view class="itemLeft">
                        <view class="unselect" @click="changeTab(1)" v-if="current == 0"></view>
                        <view class="selected" v-if="current == 1">
                            <view class="fill"></view>
                        </view>
                    </view>
                    <view class="itemRight" :style="current == 1? 'color:#1D1D1F;' : 'color: #AAAAAA' ">
                        絞り込み
                    </view>
                </view>
            </view>
            <view class="content" v-if="current == 1">
                <view class="contentItem" v-for="(item,index) in tabs" @click="toChoose(index)">
                    <view class="tabLeft">
                        <view class="tabTop" v-text="item.name"></view>
                        <view class="tabBot" v-text="item.title"></view>
                    </view>
                    <view class="tabRight">
                        <image src="../../../static/icons/right.png" mode=""></image>
                    </view>
                </view>
            </view>
            <u-button class="btn" @click="dc">CSVダウンロード</u-button>
            <view class="blank"></view>
        </view>
    </view>
</template>

<script>
    export default {
        data() {
            return {
                current: 0,
                tabs: [{
                        name: "誕生月",
                        title: "誕生月を設定"
                    },
                    {
                        name: "性別",
                        title: "性別を設定"
                    },
                    {
                        name: "来店期間",
                        title: "来店期間を設定"
                    },
                    {
                        name: "来店回数",
                        title: "来店回数を設定"
                    }
                ]
            }
        },
        methods: {
            changeTab(e) {
                this.current = e
            },
            dc() {
                const res = [
                     	{ name: "jack",
                        age: 123,
                        gender: "man"
                    },
                    {
                        name: "marry",
                        age: 666,
                        gender: "man"
                    },
                    {
                        name: "sun",
                        age: 88888888,
                        gender: "man"
                    }
                ]
                let str = res.map(m => {

                    let str2 = Object.values(m).map(mp => {
                        return `<td>${mp}</td>`
                    }).join('')
                    return `<tr>${str2}</tr>`
                }).join('')
                let str1 = Object.keys(res[0]).map(mp => {
                    return `<td>${mp}</td>`
                }).join('')
                str = `<tr>${str1}</tr>${str}`
                console.log(str);

                let template = `<html xmlns:o="urn:schemas-microsoft-com:office:office"
                     xmlns:x="urn:schemas-microsoft-com:office:excel" 
                     xmlns="http://www.w3.org/TR/REC-html40">
                     <head><!--[if gte mso 9]><xml encoding="UTF-8"><x:ExcelWorkbook><x:ExcelWorksheets><x:ExcelWorksheet>
                     <x:Name>sheet1</x:Name>
                     <x:WorksheetOptions><x:DisplayGridlines/></x:WorksheetOptions></x:ExcelWorksheet>
                     </x:ExcelWorksheets></x:ExcelWorkbook></xml><![endif]-->
                     </head><body><table>${str}</table></body></html>`;


                plus.io.requestFileSystem(plus.io.PRIVATE_DOC, function(fs) {
                    // 可通过fs进行文件操作 
                    console.log("Request file system success!");
                    console.log(fs.name);
                    fs.root.getFile(
                        `ceshi.xlsx`, {
                            create: true,
                            exclusive: false
                        },
                        fileEntry => {
                            console.log(1);
                            fileEntry.createWriter(
                                writer => {
                 					              writer.onwrite = e => {
                                        // that.count = 100;
                                        // that.tap = `成功导出[${length}]条数据，文件路径为：${e.target.fileName}`;
                                        console.log(e.target.fileName);
                                        setTimeout(function() {
                                            // that.proshow = false;
                                            uni.openDocument({
                                                filePath: `file://${e.target.fileName}`, //这里必须加file://否则会报错打不开文件
                                                success: function(res) {
                                                    console.log(res);

                                                },
                                                fail(res) {
                                                    console.log(res);
                                                }
                                            });
                                        }, 2000);
                                    };
                                    `在这里插入代码片`
                                    writer.write(template);
                                },
                                function(e) {
                                    uni.showToast({
                   						               title: '导出文件失败，请检查你的权限',
              			                       icon: 'none'
                                    });
                                }
                            );
                        },
                        e => {
                            console.log(e);
                        }

                    );

                }, function(e) {
                    alert("Request file system failed: " + e.message);
                });
            },
            toChoose(e) {
                if (e == 0) {
                    uni.navigateTo({
                        url: "../csv/birthday/birthday"
                    })
                } else if (e == 1) {
                    uni.navigateTo({
                        url: "../csv/sex/sex"
                    })
                } else if (e == 2) {
                    uni.navigateTo({
                        url: "../csv/time/time"
                    })
                } else {
                    uni.navigateTo({
                        url: "../csv/times/times"
                    })
                }
            }
        }
    }
</script>

<style lang="scss">
    .container {
        border-top: 2upx solid #D2D2D7;
        box-sizing: border-box;
        padding-top: 24upx;

        .blank {
            width: 100%;
            height: 50upx;
        }

        .btn {
            width: 478upx;
            height: 96upx;
            background: rgba(29, 29, 31, 0.1);
            border-radius: 20upx;
            opacity: 1;
            border: 2upx solid #707070;
            font-size: 40upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            margin-top: 144upx;
        }

        .content {
            border-left: 2upx solid #D2D2D7;
            border-right: 2upx solid #D2D2D7;
            border-top: 2upx solid #D2D2D7;
            margin: 32upx 0 0;
        }

        .contentItem {
            display: flex;
            align-items: center;
            justify-content: space-between;
            box-sizing: border-box;
            padding: 32upx;
            border-bottom: 2upx solid #D2D2D7;

            .tabLeft {
                .tabTop {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #1D1D1F;
                    margin-bottom: 20upx;
                }

                .tabBot {
                    font-size: 32upx;
                    font-family: Hiragino Sans-W3, Hiragino Sans;
                    font-weight: normal;
                    color: #AAAAAA;
                }
            }

            .tabRight {
                image {
                    height: 46upx;
                    width: 23upx;
                }
            }
        }


        .item {
            display: flex;
            align-items: center;
            margin-top: 60upx;

            .itemLeft {
                margin-right: 28upx;
            }

            .unselect {
                width: 40upx;
                height: 40upx;
                background: #FFFFFF;
                opacity: 1;
                box-sizing: border-box;
                border: 2upx solid #707070;
                border-radius: 50%;
            }

            .selected {
                width: 40upx;
                height: 40upx;
                background: #FFFFFF;
                border: 2upx solid #1A73E8;
                border-radius: 50%;
                box-sizing: border-box;
                padding: 6upx;

                .fill {
                    width: 100%;
                    height: 100%;
                    background: #1A73E8;
                    border-radius: 50%;
                }
            }

        }

        .mem1 {
            font-size: 28upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            text-align: right;
            margin-bottom: 14upx;
        }

        .mem2 {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #707070;
            text-align: right;

            text {
                color: #1D1D1F;
            }
        }

        .title {
            font-size: 32upx;
            font-family: Hiragino Sans-W3, Hiragino Sans;
            font-weight: normal;
            color: #1D1D1F;
            margin-top: 40upx;
        }
    }
</style>
